    54→    icon: '📊',
    55→    category: 'Work',
    56→    defaultTags: ['project'],
    57→    isBuiltIn: true,
    58→  },
    59→  {
    60→    id: 'todo-list',
    61→    name: 'Todo List',
    62→    description: '## Todo List\n\n### High Priority\n- [ ] \n\n### Medium Priority\n- [ ] \n\n### Low Priority\n- [ ] \n\n### Completed\n- [x] \n',
    63→    icon: '✅',
    64→    category: 'Productivity',
    65→    defaultTags: ['todo'],
    66→    isBuiltIn: true,
    67→  },
