     1→/**
     2→ * WikiLinkNode - Custom Lexical Node for Wiki-style Links
     3→ *
     4→ * Renders [[Note Title]] links with:
     5→ * - Visual distinction between valid/broken links
     6→ * - Click handler for broken links to create notes
     7→ * - Semantic color tokens (no hardcoded colors)
     8→ */
     9→
    10→import type {
    11→  EditorConfig,
    12→  LexicalNode,
    13→  NodeKey,
    14→  SerializedTextNode,
    15→  Spread,
    16→} from 'lexical';
    17→import { TextNode } from 'lexical';
    18→import type { Note } from '../../types/notes';
    19→
    20→export type SerializedWikiLinkNode = Spread<
    21→  {
    22→    linkTitle: string;
    23→    isBroken: boolean;
    24→  },
    25→  SerializedTextNode
    26→>;
    27→
    28→/**
    29→ * WikiLinkNode - Custom text node for wiki-style links
    30→ * Extends TextNode to preserve text editing capabilities
    31→ */
    32→export class WikiLinkNode extends TextNode {
    33→  __linkTitle: string;
    34→  __isBroken: boolean;
    35→
    36→  static getType(): string {
    37→    return 'wiki-link';
    38→  }
    39→
    40→  static clone(node: WikiLinkNode): WikiLinkNode {
    41→    return new WikiLinkNode(node.__linkTitle, node.__isBroken, node.__text, node.__key);
    42→  }
    43→
    44→  constructor(linkTitle: string, isBroken: boolean, text?: string, key?: NodeKey) {
    45→    super(text ?? `[[${linkTitle}]]`, key);
    46→    this.__linkTitle = linkTitle;
    47→    this.__isBroken = isBroken;
    48→  }
    49→
    50→  createDOM(config: EditorConfig): HTMLElement {
    51→    const element = super.createDOM(config);
    52→    element.className = this.__isBroken
    53→      ? 'wiki-link wiki-link-broken'
    54→      : 'wiki-link wiki-link-valid';
    55→
    56→    // Accessibility
    57→    element.setAttribute(
    58→      'aria-label',
    59→      this.__isBroken
    60→        ? `Broken link to ${this.__linkTitle}. Click to create note.`
    61→        : `Link to ${this.__linkTitle}`
    62→    );
    63→
    64→    // Cursor pointer for clickable links
    65→    element.style.cursor = 'pointer';
    66→
    67→    return element;
    68→  }
    69→
    70→  updateDOM(
    71→    prevNode: WikiLinkNode,
    72→    dom: HTMLElement,
    73→    config: EditorConfig
    74→  ): boolean {
    75→    // Update class if broken state changed
    76→    if (prevNode.__isBroken !== this.__isBroken) {
    77→      dom.className = this.__isBroken
    78→        ? 'wiki-link wiki-link-broken'
    79→        : 'wiki-link wiki-link-valid';
    80→
    81→      // Update aria-label
    82→      dom.setAttribute(
    83→        'aria-label',
    84→        this.__isBroken
    85→          ? `Broken link to ${this.__linkTitle}. Click to create note.`
    86→          : `Link to ${this.__linkTitle}`
    87→      );
    88→    }
    89→
    90→    // Update text content if changed
    91→    const isUpdated = super.updateDOM(prevNode as this, dom, config);
    92→    return isUpdated;
    93→  }
    94→
    95→  static importJSON(serializedNode: SerializedWikiLinkNode): WikiLinkNode {
    96→    const node = $createWikiLinkNode(
    97→      serializedNode.linkTitle,
    98→      serializedNode.isBroken
    99→    );
   100→    node.setFormat(serializedNode.format);
   101→    node.setDetail(serializedNode.detail);
   102→    node.setMode(serializedNode.mode);
   103→    node.setStyle(serializedNode.style);
   104→    return node;
   105→  }
   106→
   107→  exportJSON(): SerializedWikiLinkNode {
   108→    return {
   109→      ...super.exportJSON(),
   110→      linkTitle: this.__linkTitle,
   111→      isBroken: this.__isBroken,
   112→      type: 'wiki-link',
   113→      version: 1,
   114→    };
   115→  }
   116→
   117→  getLinkTitle(): string {
   118→    return this.__linkTitle;
   119→  }
   120→
   121→  getIsBroken(): boolean {
   122→    return this.__isBroken;
   123→  }
   124→
   125→  setIsBroken(isBroken: boolean): void {
   126→    const writable = this.getWritable();
   127→    writable.__isBroken = isBroken;
   128→  }
   129→}
   130→
   131→/**
   132→ * Helper function to create WikiLinkNode
   133→ */
   134→export function $createWikiLinkNode(
   135→  linkTitle: string,
   136→  isBroken: boolean
   137→): WikiLinkNode {
   138→  return new WikiLinkNode(linkTitle, isBroken);
   139→}
   140→
   141→/**
   142→ * Type guard for WikiLinkNode
   143→ */
   144→export function $isWikiLinkNode(
   145→  node: LexicalNode | null | undefined
   146→): node is WikiLinkNode {
   147→  return node instanceof WikiLinkNode;
   148→}
   149→
   150→/**
   151→ * Utility: Check if a link title is broken (doesn't resolve to a note)
   152→ */
   153→export function isLinkBroken(linkTitle: string, allNotes: Record<string, Note>): boolean {
   154→  const notesArray = Object.values(allNotes);
   155→  const titleLower = linkTitle.toLowerCase();
   156→
