     1→import { useState, useEffect, useCallback } from 'react';
     2→import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
     3→import { $getSelection, $isRangeSelection, TextNode } from 'lexical';
     4→import type { Note } from '../../types/notes';
     5→import { useFoldersStore } from '../../stores/useFoldersStore';
     6→import AutocompleteDropdown from './AutocompleteDropdown';
     7→
     8→interface WikiLinkAutocompletePluginProps {
     9→  notes: Note[];
    10→  currentFolderId?: string | null;
    11→}
    12→
    13→/**
    14→ * WikiLinkAutocompletePlugin
    15→ *
    16→ * Lexical plugin that provides autocomplete for wiki-style links ([[Note Title]]).
    17→ *
    18→ * Features:
    19→ * - Detects [[ pattern in editor
    20→ * - Shows autocomplete dropdown
    21→ * - Inserts selected note title as [[Title]]
    22→ * - Positions dropdown near cursor
    23→ */
    24→export default function WikiLinkAutocompletePlugin({
    25→  notes,
    26→  currentFolderId,
    27→}: WikiLinkAutocompletePluginProps) {
    28→  const [editor] = useLexicalComposerContext();
    29→  const [query, setQuery] = useState<string | null>(null);
    30→  const [position, setPosition] = useState<{ top: number; left: number } | null>(null);
    31→  const getPath = useFoldersStore((state) => state.getPath);
    32→
    33→  // Get folder path helper
    34→  const getFolderPath = useCallback(
    35→    (folderId: string | null): string => {
    36→      if (!folderId) return 'Root';
    37→      const path = getPath(folderId);
    38→      if (!path || path.length === 0) return 'Root';
    39→      return path.map(folder => folder.name).join(' / ');
    40→    },
    41→    [getPath]
    42→  );
    43→
    44→  // Get cursor position for dropdown placement
    45→  const getCursorPosition = useCallback((): { top: number; left: number } | null => {
    46→    const selection = window.getSelection();
    47→    if (!selection || selection.rangeCount === 0) return null;
    48→
    49→    const range = selection.getRangeAt(0);
    50→    const rect = range.getBoundingClientRect();
    51→
    52→    // Position dropdown below cursor (or above if no space)
    53→    const top = rect.bottom + window.scrollY + 4;
    54→    const left = rect.left + window.scrollX;
    55→
    56→    // Check if dropdown would go off-screen vertically
    57→    const dropdownHeight = 300; // Approximate max height
    58→    const viewportHeight = window.innerHeight;
    59→
    60→    if (rect.bottom + dropdownHeight > viewportHeight) {
    61→      // Show above cursor instead
    62→      return {
    63→        top: rect.top + window.scrollY - dropdownHeight - 4,
    64→        left,
    65→      };
    66→    }
    67→
    68→    return { top, left };
    69→  }, []);
    70→
    71→  // Listen for text changes and detect [[ pattern
    72→  useEffect(() => {
    73→    return editor.registerUpdateListener(({ editorState }) => {
    74→      editorState.read(() => {
    75→        const selection = $getSelection();
    76→        if (!$isRangeSelection(selection)) {
    77→          setQuery(null);
    78→          return;
    79→        }
    80→
    81→        const anchorNode = selection.anchor.getNode();
    82→        if (!(anchorNode instanceof TextNode)) {
    83→          setQuery(null);
    84→          return;
    85→        }
    86→
    87→        const text = anchorNode.getTextContent();
    88→        const offset = selection.anchor.offset;
    89→
    90→        // Look for [[ pattern before cursor
    91→        const textBeforeCursor = text.slice(0, offset);
    92→        const match = textBeforeCursor.match(/\[\[([^\]]*?)$/);
    93→
    94→        if (match) {
    95→          const searchQuery = match[1];
    96→          setQuery(searchQuery);
    97→          const pos = getCursorPosition();
    98→          setPosition(pos);
    99→        } else {
   100→          setQuery(null);
   101→        }
   102→      });
   103→    });
   104→  }, [editor, getCursorPosition]);
   105→
   106→  // Handle note selection
   107→  const handleSelect = useCallback(
   108→    (title: string) => {
   109→      editor.update(() => {
   110→        const selection = $getSelection();
   111→        if (!$isRangeSelection(selection)) return;
   112→
   113→        const anchorNode = selection.anchor.getNode();
   114→        if (!(anchorNode instanceof TextNode)) return;
   115→
   116→        const text = anchorNode.getTextContent();
   117→        const offset = selection.anchor.offset;
   118→
   119→        // Find the [[ before cursor
   120→        const textBeforeCursor = text.slice(0, offset);
   121→        const match = textBeforeCursor.match(/\[\[([^\]]*?)$/);
   122→
   123→        if (!match) return;
   124→
   125→        const matchStart = textBeforeCursor.lastIndexOf('[[');
   126→        const beforeMatch = text.slice(0, matchStart);
   127→        const afterCursor = text.slice(offset);
   128→
   129→        // Replace [[query with [[Title]]
   130→        const newText = `${beforeMatch}[[${title}]]${afterCursor}`;
   131→
   132→        // Update node text
   133→        anchorNode.setTextContent(newText);
   134→
   135→        // Move cursor to after ]]
   136→        const newOffset = matchStart + title.length + 4; // [[ + title + ]]
   137→        selection.anchor.offset = newOffset;
   138→        selection.focus.offset = newOffset;
   139→      });
   140→
   141→      setQuery(null);
   142→    },
   143→    [editor]
   144→  );
   145→
   146→  // Handle cancel
   147→  const handleCancel = useCallback(() => {
   148→    setQuery(null);
   149→  }, []);
   150→
   151→  if (query === null) return null;
   152→
   153→  return (
   154→    <AutocompleteDropdown
   155→      query={query}
   156→      notes={notes}
   157→      position={position}
   158→      onSelect={handleSelect}
   159→      onCancel={handleCancel}
   160→      currentFolderId={currentFolderId}
   161→      getFolderPath={getFolderPath}
   162→    />
   163→  );
   164→}
