   453→
   454→  const toggleAutoSave = async () => {
   455→    if (!preferences) return;
   456→
   457→    if (preferences.autoSaveEnabled) {
   458→      // Disable auto-save
   459→      await autoSaveManager.disableLocal();
   460→      setAutoSaveDirectory(null);
   461→      await loadAllData();
   462→      setMessage({ type: 'info', text: 'Auto-save disabled' });
   463→
   464→      // Show visual feedback
   465→      setRecentlySaved('autoSave');
   466→      setTimeout(() => setRecentlySaved(null), 2000);
   467→    } else {
   468→      // Enable auto-save - request directory
