                          <span className="font-semibold text-text-light-primary dark:text-text-dark-primary">
                            {storageInfo.quotaFormatted}
                          </span>
                        </div>

                        {/* Progress Bar */}
                        <div className="mt-3">
                          <div className="w-full bg-neutral-300 dark:bg-neutral-700 rounded-full h-3 overflow-hidden">
                            <div
                              className={`h-3 rounded-full transition-all duration-300 ${
                                storageInfo.percentUsed > 80 ? 'bg-status-error' :
                                storageInfo.percentUsed > 60 ? 'bg-status-warning' :
                                'bg-status-success'
                              }`}
                              style={{ width: `${Math.min(storageInfo.percentUsed, 100)}%` }}
                            />
                          </div>
                          <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                            {storageInfo.percentUsed.toFixed(1)}% used
                            {storageInfo.percentUsed > 80 && (
                              <span className="text-status-error-text dark:text-status-error-text-dark ml-2">
                                ⚠️ Running low on space
                              </span>
                            )}
                          </p>
                        </div>
                      </div>
                    ) : (
                      <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                        Loading storage info...
                      </p>
                    )}
                  </div>

                  {/* Last Backup Info */}
                  <div>
                    <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
                      Last Backup
                    </h3>
                    {backupHistory.length > 0 ? (
                      <div className="p-4 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg space-y-2">
                        <div className="flex justify-between text-sm">
                          <span className="text-text-light-secondary dark:text-text-dark-secondary">Time:</span>
                          <span className="font-semibold text-text-light-primary dark:text-text-dark-primary">
                            {new Date(backupHistory[0].timestamp).toLocaleString()}
                          </span>
                        </div>
                        <div className="flex justify-between text-sm">
                          <span className="text-text-light-secondary dark:text-text-dark-secondary">Size:</span>
                          <span className="font-semibold text-text-light-primary dark:text-text-dark-primary">
                            {formatFileSize(backupHistory[0].size)}
                          </span>
                        </div>
                        <div className="flex justify-between text-sm">
                          <span className="text-text-light-secondary dark:text-text-dark-secondary">Status:</span>
                          <span className={`font-semibold ${
                            backupHistory[0].status === 'success'
                              ? 'text-status-success-text dark:text-status-success-text-dark'
                              : 'text-status-error-text dark:text-status-error-text-dark'
                          }`}>
                            {backupHistory[0].status === 'success' ? '✅ Success' : '❌ Failed'}
                          </span>
                        </div>
                        {backupHistory[0].compressed && (
                          <div className="flex justify-between text-sm">
                            <span className="text-text-light-secondary dark:text-text-dark-secondary">Compressed:</span>
                            <span className="font-semibold text-status-success-text dark:text-status-success-text-dark">
                              ✅ Yes (~70% smaller)
                            </span>
                          </div>
                        )}
                      </div>
                    ) : (
                      <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary p-4 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg">
                        No backups yet. Create your first backup above!
                      </p>
                    )}
                  </div>

                  {/* Browser Info */}
                  <div>
                    <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
                      Browser & Capabilities
                    </h3>
                    <div className="p-4 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg space-y-2">
                      <div className="flex justify-between text-sm">
                        <span className="text-text-light-secondary dark:text-text-dark-secondary">Browser:</span>
                        <span className="font-mono text-xs text-text-light-primary dark:text-text-dark-primary">
                          {navigator.userAgent.match(/(?:Firefox|Chrome|Safari|Edge)\/[\d.]+/)?.[0] || 'Unknown'}
                        </span>
                      </div>
                      <div className="flex justify-between text-sm">
                        <span className="text-text-light-secondary dark:text-text-dark-secondary">IndexedDB:</span>
                        <span className="font-semibold text-status-success-text dark:text-status-success-text-dark">
                          ✅ Supported
                        </span>
                      </div>
                      <div className="flex justify-between text-sm">
                        <span className="text-text-light-secondary dark:text-text-dark-secondary">File System Access API:</span>
                        <span className={`font-semibold ${
                          isFileSystemAccessSupported()
                            ? 'text-status-success-text dark:text-status-success-text-dark'
                            : 'text-status-warning-text dark:text-status-warning-text-dark'
                        }`}>
                          {isFileSystemAccessSupported() ? '✅ Supported' : '⚠️ Not Supported'}
                        </span>
                      </div>
                      {!isFileSystemAccessSupported() && (
                        <p className="text-xs text-status-warning-text dark:text-status-warning-text-dark mt-2 p-2 bg-status-warning-bg dark:bg-status-warning-bg-dark rounded">
                          Auto-save to folder requires a Chromium-based browser (Chrome, Edge, Brave, Arc, Opera, etc.). Manual export/import still works!
                        </p>
                      )}
                    </div>
                  </div>
                </motion.div>
              )}
            </div>

      </div>

      {/* Background Customizer Modal */}
      <BackgroundCustomizer
        isOpen={showBackgroundCustomizer}
        onClose={() => setShowBackgroundCustomizer(false)}
        settings={bgSettings}
        onSettingsChange={handleBackgroundChange}
      />

      {/* Preset Manager Modal */}
      <PresetManager
        isOpen={showPresetManager}
        onClose={() => setShowPresetManager(false)}
      />
    </div>
  );
};

