/**
 * Tag Manager Component
 *
 * Centralized tag management UI with operations:
 * - View all tags with usage counts (hierarchical display)
 * - Rename tags globally (update across all notes)
 * - Merge tags (combine similar tags)
 * - Delete tags (remove from all notes)
 * - Search/filter tags
 * - Sort by name or usage count
 */

import { useState, useMemo } from 'react';
import { X, Search, Edit2, Trash2, GitMerge, ChevronRight, ChevronDown } from 'lucide-react';
import { useNotesStore } from '../stores/useNotesStore';
import { buildTagTree, type TagNode } from '../utils/tagHierarchy';
import { Modal } from './Modal';
import { ConfirmDialog } from './ConfirmDialog';

interface TagManagerProps {
  /** Callback when tag manager is closed */
  onClose?: () => void;
}

export function TagManager({ onClose }: TagManagerProps) {
  // State
  const [searchQuery, setSearchQuery] = useState('');
  const [sortBy, setSortBy] = useState<'name' | 'count'>('name');
  const [expandedTags, setExpandedTags] = useState<Set<string>>(new Set());

  // Rename modal
  const [renameModalOpen, setRenameModalOpen] = useState(false);
  const [tagToRename, setTagToRename] = useState<string>('');
  const [newTagName, setNewTagName] = useState('');

  // Merge modal
  const [mergeModalOpen, setMergeModalOpen] = useState(false);
  const [sourceTags, setSourceTags] = useState<Set<string>>(new Set());
  const [targetTag, setTargetTag] = useState('');

  // Delete confirmation
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [tagToDelete, setTagToDelete] = useState<string>('');
  const [deleteAffectedCount, setDeleteAffectedCount] = useState(0);

  // Store access
  const allTags = useNotesStore((state) => state.getAllTags());
  const getTagUsageCounts = useNotesStore((state) => state.getTagUsageCounts);
  const renameTag = useNotesStore((state) => state.renameTag);
  const mergeTags = useNotesStore((state) => state.mergeTags);
  const deleteTag = useNotesStore((state) => state.deleteTag);

  // Get usage counts
  const tagCounts = useMemo(() => getTagUsageCounts(), [getTagUsageCounts]);

  // Filter tags by search query
  const filteredTags = useMemo(() => {
    if (!searchQuery.trim()) return allTags;
    const query = searchQuery.toLowerCase();
    return allTags.filter((tag) => tag.toLowerCase().includes(query));
  }, [allTags, searchQuery]);

  // Build tag tree from filtered tags
  const tagTree = useMemo(() => {
    const counts = Object.fromEntries(tagCounts);
    return buildTagTree(filteredTags, counts);
  }, [filteredTags, tagCounts]);

  // Sort tags
  const sortedTree = useMemo(() => {
    const sortNodes = (nodes: TagNode[]): TagNode[] => {
      const sorted = [...nodes].sort((a, b) => {
        if (sortBy === 'name') {
          return a.label.localeCompare(b.label);
        } else {
          return b.noteCount - a.noteCount;
        }
      });

      return sorted.map((node) => ({
        ...node,
        children: sortNodes(node.children),
      }));
    };

    return sortNodes(tagTree);
  }, [tagTree, sortBy]);

  // Toggle expansion
  const toggleExpand = (tag: string) => {
    setExpandedTags((prev) => {
      const next = new Set(prev);
      if (next.has(tag)) {
        next.delete(tag);
      } else {
        next.add(tag);
      }
      return next;
    });
  };

  // Open rename modal
  const handleRenameClick = (tag: string) => {
    setTagToRename(tag);
    setNewTagName(tag);
    setRenameModalOpen(true);
  };

  // Perform rename
  const handleRenameSubmit = () => {
    if (!newTagName.trim() || newTagName === tagToRename) {
      setRenameModalOpen(false);
      return;
    }

    renameTag(tagToRename, newTagName.trim());
    setRenameModalOpen(false);
    setTagToRename('');
    setNewTagName('');
  };

  // Toggle tag selection for merge
  const toggleMergeSelection = (tag: string) => {
    setSourceTags((prev) => {
      const next = new Set(prev);
      if (next.has(tag)) {
        next.delete(tag);
      } else {
        next.add(tag);
      }
      return next;
    });
  };

  // Open merge modal
  const handleMergeClick = () => {
    if (sourceTags.size === 0) return;
    setMergeModalOpen(true);
  };

  // Perform merge
  const handleMergeSubmit = () => {
    if (!targetTag.trim() || sourceTags.size === 0) {
      setMergeModalOpen(false);
      return;
    }

    mergeTags(Array.from(sourceTags), targetTag.trim());
    setMergeModalOpen(false);
    setSourceTags(new Set());
    setTargetTag('');
  };

  // Open delete confirmation
  const handleDeleteClick = (tag: string) => {
    const count = tagCounts.get(tag) || 0;
    setTagToDelete(tag);
    setDeleteAffectedCount(count);
    setDeleteDialogOpen(true);
  };

  // Perform delete
  const handleDeleteConfirm = () => {
    deleteTag(tagToDelete);
    setDeleteDialogOpen(false);
    setTagToDelete('');
    setDeleteAffectedCount(0);
  };

  // Render tag node recursively
  const renderTagNode = (node: TagNode): React.ReactNode => {
    const hasChildren = node.children.length > 0;
    const isExpanded = expandedTags.has(node.name);
    const isSelected = sourceTags.has(node.name);

    return (
      <div key={node.name}>
        {/* Tag row */}
        <div
          className="group flex items-center gap-2 px-3 py-2 hover:bg-surface-light dark:hover:bg-surface-dark transition-colors rounded"
          style={{ paddingLeft: `${node.level * 16 + 12}px` }}
        >
          {/* Expand/collapse button */}
          {hasChildren && (
            <button
              onClick={() => toggleExpand(node.name)}
              className="flex-shrink-0 p-1 hover:bg-border-light dark:hover:bg-border-dark rounded transition-colors"
              aria-label={isExpanded ? 'Collapse' : 'Expand'}
            >
              {isExpanded ? (
                <ChevronDown className="w-4 h-4 text-text-light-tertiary dark:text-text-dark-tertiary" />
              ) : (
                <ChevronRight className="w-4 h-4 text-text-light-tertiary dark:text-text-dark-tertiary" />
              )}
            </button>
          )}
          {!hasChildren && <span className="w-6" />}

          {/* Merge checkbox */}
          <input
            type="checkbox"
            checked={isSelected}
            onChange={() => toggleMergeSelection(node.name)}
            className="flex-shrink-0 w-4 h-4 rounded border-border-light dark:border-border-dark"
            aria-label={`Select ${node.name} for merging`}
          />

          {/* Tag name + count */}
          <div className="flex-1 flex items-center gap-2 min-w-0">
            <span className="text-text-light-primary dark:text-text-dark-primary truncate">
              {node.label}
            </span>
            <span className="flex-shrink-0 px-2 py-0.5 text-xs font-medium rounded bg-accent-purple/10 text-accent-purple dark:bg-accent-cyan/10 dark:text-accent-cyan">
              {node.noteCount}
            </span>
          </div>

          {/* Action buttons (hidden until hover) */}
          <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
            <button
              onClick={() => handleRenameClick(node.name)}
              className="p-1.5 hover:bg-accent-blue/10 text-accent-blue rounded transition-colors"
              aria-label={`Rename ${node.name}`}
              title="Rename"
            >
              <Edit2 className="w-4 h-4" />
            </button>
            <button
              onClick={() => handleDeleteClick(node.name)}
              className="p-1.5 hover:bg-status-error/10 text-status-error rounded transition-colors"
              aria-label={`Delete ${node.name}`}
              title="Delete"
            >
              <Trash2 className="w-4 h-4" />
            </button>
          </div>
        </div>

        {/* Render children if expanded */}
        {hasChildren && isExpanded && (
          <div>{node.children.map((child) => renderTagNode(child))}</div>
        )}
      </div>
    );
  };

  return (
    <>
      <div className="h-full flex flex-col">
        {/* Header */}
        <div className="flex-shrink-0 flex items-center justify-between p-4 border-b border-border-light dark:border-border-dark">
          <h2 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary">
            Tag Manager
          </h2>
          {onClose && (
            <button
              onClick={onClose}
              className="p-2 hover:bg-surface-light dark:hover:bg-surface-dark rounded transition-colors"
              aria-label="Close"
            >
              <X className="w-5 h-5 text-text-light-secondary dark:text-text-dark-secondary" />
            </button>
          )}
        </div>

        {/* Controls */}
        <div className="flex-shrink-0 p-4 space-y-3 border-b border-border-light dark:border-border-dark">
          {/* Search */}
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-text-light-tertiary dark:text-text-dark-tertiary" />
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search tags..."
              className="w-full pl-10 pr-4 py-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded focus:outline-none focus:ring-2 focus:ring-accent-purple dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
            />
          </div>

          {/* Sort + Merge */}
          <div className="flex items-center gap-2">
            {/* Sort toggle */}
            <div className="flex items-center gap-2">
              <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                Sort by:
              </span>
              <button
                onClick={() => setSortBy('name')}
                className={`px-3 py-1.5 text-sm rounded transition-colors ${
                  sortBy === 'name'
                    ? 'bg-accent-purple text-white dark:bg-accent-cyan'
                    : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary hover:bg-border-light dark:hover:bg-border-dark'
                }`}
              >
                Name
              </button>
              <button
                onClick={() => setSortBy('count')}
                className={`px-3 py-1.5 text-sm rounded transition-colors ${
                  sortBy === 'count'
                    ? 'bg-accent-purple text-white dark:bg-accent-cyan'
                    : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary hover:bg-border-light dark:hover:bg-border-dark'
                }`}
              >
                Count
              </button>
            </div>

            {/* Merge button */}
            <button
              onClick={handleMergeClick}
              disabled={sourceTags.size === 0}
              className="ml-auto flex items-center gap-2 px-3 py-1.5 text-sm bg-accent-blue text-white rounded hover:bg-accent-blue-hover transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            >
              <GitMerge className="w-4 h-4" />
              Merge {sourceTags.size > 0 && `(${sourceTags.size})`}
            </button>
          </div>

          {/* Stats */}
          <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
            {filteredTags.length} tag{filteredTags.length !== 1 ? 's' : ''} •{' '}
            {Array.from(tagCounts.values()).reduce((sum, count) => sum + count, 0)} total uses
          </div>
        </div>

        {/* Tag list */}
        <div className="flex-1 overflow-y-auto">
          {sortedTree.length === 0 ? (
            <div className="p-8 text-center text-text-light-secondary dark:text-text-dark-secondary">
              {searchQuery ? 'No tags match your search' : 'No tags yet'}
            </div>
          ) : (
            <div className="py-2">{sortedTree.map((node) => renderTagNode(node))}</div>
          )}
        </div>
      </div>

      {/* Rename Modal */}
      <Modal
        isOpen={renameModalOpen}
        onClose={() => setRenameModalOpen(false)}
        title="Rename Tag"
        maxWidth="md"
      >
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
              Current Name
            </label>
            <input
              type="text"
              value={tagToRename}
              disabled
              className="w-full px-3 py-2 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded text-text-light-secondary dark:text-text-dark-secondary"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
              New Name
            </label>
            <input
              type="text"
              value={newTagName}
              onChange={(e) => setNewTagName(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleRenameSubmit()}
              placeholder="Enter new tag name"
              autoFocus
              className="w-full px-3 py-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded focus:outline-none focus:ring-2 focus:ring-accent-purple dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
            />
          </div>

          <div className="flex items-center justify-end gap-2">
            <button
              onClick={() => setRenameModalOpen(false)}
              className="px-4 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary rounded hover:bg-border-light dark:hover:bg-border-dark transition-colors"
            >
              Cancel
            </button>
            <button
              onClick={handleRenameSubmit}
              disabled={!newTagName.trim() || newTagName === tagToRename}
              className="px-4 py-2 text-sm bg-accent-purple text-white rounded hover:bg-accent-purple-hover transition-colors disabled:opacity-50 disabled:cursor-not-allowed dark:bg-accent-cyan dark:hover:bg-accent-cyan-hover"
            >
              Rename
            </button>
          </div>
        </div>
      </Modal>

      {/* Merge Modal */}
      <Modal
        isOpen={mergeModalOpen}
        onClose={() => setMergeModalOpen(false)}
        title="Merge Tags"
        maxWidth="md"
      >
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
              Source Tags (will be replaced)
            </label>
            <div className="flex flex-wrap gap-2 p-3 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded">
              {Array.from(sourceTags).map((tag) => (
                <span
                  key={tag}
                  className="inline-flex items-center gap-1 px-2 py-1 text-xs font-medium rounded bg-accent-purple/10 text-accent-purple dark:bg-accent-cyan/10 dark:text-accent-cyan"
                >
                  {tag}
                  <button
                    onClick={() => toggleMergeSelection(tag)}
                    className="hover:bg-accent-purple/20 dark:hover:bg-accent-cyan/20 rounded p-0.5 transition-colors"
                  >
                    <X className="w-3 h-3" />
                  </button>
                </span>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
              Target Tag (keep this one)
            </label>
            <input
              type="text"
              value={targetTag}
              onChange={(e) => setTargetTag(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleMergeSubmit()}
              placeholder="Enter target tag name"
              autoFocus
              className="w-full px-3 py-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded focus:outline-none focus:ring-2 focus:ring-accent-purple dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
            />
            <p className="mt-1 text-xs text-text-light-secondary dark:text-text-dark-secondary">
              All notes with source tags will be updated to use the target tag
            </p>
          </div>

          <div className="flex items-center justify-end gap-2">
            <button
              onClick={() => setMergeModalOpen(false)}
              className="px-4 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary rounded hover:bg-border-light dark:hover:bg-border-dark transition-colors"
            >
              Cancel
            </button>
            <button
              onClick={handleMergeSubmit}
              disabled={!targetTag.trim() || sourceTags.size === 0}
              className="px-4 py-2 text-sm bg-accent-blue text-white rounded hover:bg-accent-blue-hover transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Merge
            </button>
          </div>
        </div>
      </Modal>

      {/* Delete Confirmation */}
      <ConfirmDialog
        isOpen={deleteDialogOpen}
        onClose={() => setDeleteDialogOpen(false)}
        onConfirm={handleDeleteConfirm}
        title="Delete Tag"
        message={`Are you sure you want to delete "${tagToDelete}"? This will remove it from ${deleteAffectedCount} note${deleteAffectedCount !== 1 ? 's' : ''}.`}
        confirmText="Delete"
        cancelText="Cancel"
        variant="danger"
      />
    </>
  );
}

